// friday13.cs — Friday the 13th experiments with the proleptic Gregorian calendar

// Find the earliest Friday the 13th starting from 0001-01-01
var date = new DateTime(1, 1, 13); // start checking the 13th of each month
DateTime? earliest = null;

while (date.Year <= 400)
{
    if (date.DayOfWeek == DayOfWeek.Friday)
    {
        earliest ??= date;
        break;
    }
    date = date.AddMonths(1);
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");
Console.WriteLine();

// Count all Friday the 13ths in a full 400-year cycle (the Gregorian calendar repeats every 400 years)
int count = 0;
var check = new DateTime(1, 1, 13);
var end = new DateTime(401, 1, 1);

while (check < end)
{
    if (check.DayOfWeek == DayOfWeek.Friday)
        count++;
    check = check.AddMonths(1);
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"That's an average of {count / 400.0:F4} per year, or about one every {4800.0 / count:F2} months.");

